using System.Text;using System.Text.Json; namespace BarberSync.PublicWeb.Services; public class ApiClient(HttpClient http):IApiClient{public async Task<T?> GetAsync<T>(string u)=>JsonSerializer.Deserialize<T>(await http.GetStringAsync(u)); public async Task<T?> PostAsync<T>(string u,object b){var r=await http.PostAsync(u,new StringContent(JsonSerializer.Serialize(b),Encoding.UTF8,"application/json"));return JsonSerializer.Deserialize<T>(await r.Content.ReadAsStringAsync());}}
